/*
Longest Valid Parenthesis

Given a string containing just the characters '(' and ')', return the length of the longest valid (well-formed) parentheses substring.

Example 1:

Input: s = "(()"
Output: 2
Explanation: The longest valid parentheses substring is "()"

Example 2:

Input: s = ")()())"
Output: 4
Explanation: The longest valid parentheses substring is "()()".

Example 3:

Input: s = ""
Output: 0

Constraints:
    30000 * 30000 = 900000000
    0 <= s.length <= 3 * 10^4
    s[i] is '(', or ')'.

 */
#include <bits/stdc++.h>
using namespace std;

void checkForValidParentheses(string &s, int leftIndex, int rightIndex, int *result) {
    stack<char> pstack;
    for (int i=leftIndex; i<=rightIndex; i++) {
        char val = s[i];

        if (val == '(') {
            pstack.push(val);
        } else {
            if (pstack.empty()) {
                return;
            }
            if (pstack.top() == '(') {
                pstack.pop();
            } else {
                return;
            }
        }
    }

    if (pstack.empty()) {
        // cout << "Found result for : " << leftIndex << " " << rightIndex << endl;
        int currentResult = rightIndex - leftIndex + 1;
        if (currentResult > *result) {
            // cout << "Updating result: " << endl;
            *result = rightIndex - leftIndex + 1;
        }
        // cout << "Result: " << *result << endl;
    }
}

void getLongestParentheses(string &s, int leftIndex, int rightIndex, int *result, int left, int right, unordered_map<int, int> &dict) {
    // cout << "Left Index : " << leftIndex << " Left count: " << left << endl;
    // cout << "Right Index: " << rightIndex << " Right count: " << right << endl;
    // cout << endl;

    int key = 30000 * leftIndex + rightIndex;
    if (dict.find(key) != dict.end()) {
        return;
    }

    if (left == right) {
        // cout << "Finding Result:" << endl;
        checkForValidParentheses(s, leftIndex, rightIndex, result);
        dict.insert({key, *result});
    }


    if (s[leftIndex] == '(') {
        key = 30000 * (leftIndex+1) + rightIndex;
        if (dict.find(key) == dict.end() && left - 1 > 0 && leftIndex+1 < rightIndex) {
            getLongestParentheses(s, leftIndex+1, rightIndex, result, left - 1, right, dict);
            dict.insert({key, *result});
        }
    }

    if (s[leftIndex] == ')') {
        key = 30000 * (leftIndex+1) + rightIndex;
        if (dict.find(key) == dict.end() && right - 1 > 0 && leftIndex + 1 < rightIndex) {
            getLongestParentheses(s, leftIndex+1, rightIndex, result, left, right-1, dict);
            dict.insert({key, *result});
        }

    }

    if (s[rightIndex] == '(') {
        key = 30000 * leftIndex + rightIndex-1;
        if (dict.find(key) == dict.end() && left - 1 > 0 && leftIndex < rightIndex - 1) {
            getLongestParentheses(s, leftIndex, rightIndex-1, result, left-1, right, dict);
            dict.insert({key, *result});
        }
    }

    if (s[rightIndex] == ')') {
        key = 30000 * leftIndex + rightIndex-1;
        if (dict.find(key) == dict.end() && right - 1 > 0 && leftIndex < rightIndex - 1) {
            getLongestParentheses(s, leftIndex, rightIndex-1, result, left, right-1, dict);
            dict.insert({key, *result});
        }
    }
}

int longestValidParenthesesPrevious(string s) {
    int result = 0;

    // Try it our way first
    int left = 0;
    int right = 0;
    for (int i=0; i<s.size(); i++) {
        if (s[i] == '(') {
            left++;
        } else {
            right++;
        }
    }
    // cout << "Left: " << left << endl;
    // cout << "Right: " << right << endl;

    int leftIndex = 0;
    int rightIndex = s.size() - 1;
    unordered_map<int, int> dict;
    stack<char> pstack;
    getLongestParentheses(s, leftIndex, rightIndex, &result, left, right, dict);

    return result;
}

int longestValidParentheses(string s) {
    int result = 0;

    // why initialize it with -1?
    stack<int> st;
    st.push(-1);

    for (int i=0; i<s.size(); i++) {
        char val = s[i];
        if (val == '(') {
            // always push the index
            st.push(i);
        } else {
            // val is ')'
            st.pop();

            // Ignore if stack is empty
            if (st.empty()) {
                // We push this index here because this is the breakpoint of valid parentheses
                st.push(i);
            } else {
                // if non empty
                int topIndex = st.top();
                int currentMax = i - topIndex;
                result = max(result, currentMax);
            }
        }
    }

    return result;
}

